function timeoutOnHours(hours, min, sec, mil) {
    const target = new Date()
    const now = new Date()

    target.setHours(hours, min, sec, mil)

    let left = target.getTime() - now.getTime()
    setTimeout(() => {
        console.log("🔥 WAKTU TEPAT!")
        location.href = 'https://shopee.co.id/Apple-iPhone-16-i.241308147.25992970267';

        const sections = [...document.querySelectorAll('.j7HL5Q')]
        sections.forEach(element => {
            const button = [...element.querySelectorAll('button')].find(v => v.getAttribute('aria-disabled') == 'false')
            button.click()
        });
    }, left)
}

function jadwalkanAutomasi() {
    const sekarang = new Date();
    const waktuTarget = new Date();

    // Atur waktu target ke jam 12:00:00.000 
    // CATATAN: Jika flash sale jam 12 malam (pergantian hari), gunakan angka 0 untuk jam.
    // Format: setHours(jam, menit, detik, milidetik)
    waktuTarget.setHours(20, 0, 0, 500);

    // Jika waktu sekarang ternyata sudah melewati jam 12 hari ini, 
    // atur target ke jam 12 besok harinya agar hitungannya tidak minus.
    if (sekarang.getTime() >= waktuTarget.getTime()) {
        waktuTarget.setDate(waktuTarget.getDate() + 1);
    }

    // Hitung selisih waktu dalam milidetik
    let selisihMilidetik = waktuTarget.getTime() - sekarang.getTime();

    // [OPSIONAL] Trik Jaringan: Kurangi beberapa milidetik (misal 50ms) 
    // untuk mengkompensasi delay ping/jaringan agar request sampai ke server Shopee tepat jam 12:00:00.
    // selisihMilidetik = selisihMilidetik - 50; 

    console.log(`⏳ Menunggu ${selisihMilidetik} milidetik menuju eksekusi...`);

    // Pasang timer
    setTimeout(() => {
        console.log("🔥 WAKTU TEPAT! Menembak API sekarang...");

        // Panggil fungsi utama bot kamu di sini
        runBot();

    }, selisihMilidetik);

    setInterval(() => {
        const left = waktuTarget.getTime() - new Date().getTime()
        console.log(`Sisa ${left} milidetik lagi menuju eksekusi...`)
    }, 1000 * 60)
}

// Jalankan penjadwalannya (misalnya saat halaman web Shopee selesai dimuat)
jadwalkanAutomasi();